+        // Our tags: hi & 0xFFFF0000 in {0x7FF90000, 0x7FFA0000, ..., 0x7FFF0000}
+        // Actual NaN: hi & 0xFFFF0000 == 0x7FF80000
+        const tag_bits = self.hi & 0xFFFF0000;
+        return tag_bits == 0x7FF80000; // Actual NaN (not our tagged value)
     }

